// friday13.cs â€” Find earliest Friday the 13th and count them in a 400-year cycle

// Earliest Friday the 13th starting from 0001-01-01 (proleptic Gregorian)
var date = new DateOnly(1, 1, 13);
while (date.DayOfWeek != DayOfWeek.Friday)
    date = date.AddMonths(1);

Console.WriteLine($"Earliest Friday the 13th: {date:yyyy-MM-dd}");

// Count Friday the 13ths in a full 400-year cycle (0001-01-13 to 0400-12-13)
int count = 0;
var d = new DateOnly(1, 1, 13);
var end = new DateOnly(400, 12, 13);
while (d <= end)
{
    if (d.DayOfWeek == DayOfWeek.Friday)
        count++;
    d = d.AddMonths(1);
}

Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");

// Bonus: distribution by day of week for the 13th
var dayCounts = new int[7];
d = new DateOnly(1, 1, 13);
while (d <= end)
{
    dayCounts[(int)d.DayOfWeek]++;
    d = d.AddMonths(1);
}

Console.WriteLine("\nDistribution of the 13th by day of week (400-year cycle):");
foreach (DayOfWeek dow in Enum.GetValues<DayOfWeek>())
    Console.WriteLine($"  {dow,-9}: {dayCounts[(int)dow]}");

